function EntityListener.onSpawnEntity(lEntity)
    if lEntity and lEntity.type == EntityType.SessionNpc then
        LuaTimer:schedule(function()
            if lEntity.entity and lEntity.entity:getActorName() == "g1008_diamond.actor" then
                lEntity.entity:setBoolProperty("banClicked", true)
            end
        end, 1000)
    end
end

function EntityListener.onAttackActorNpc(entityId)
    local entity = EntityCache:getEntity(entityId)
    if entity == nil then
        return true
    end
    local type = entity.entity:getIntProperty("Type")
    if type == StoreNpcType.Goods then
        GUIStore:show(StoreId.GoodsStore)
        return false
    end
    if type == StoreNpcType.Upgrade then
        GUIUpgradeStore:show(StoreId.UpgradeStore)
        return false
    end
    return true
end